css:
/*【主流杂志｜粉白】作者：易碎蝶
①本美化免费发布于QQ小群（或可能本人发在旅程），禁止二传二改
②部分代码用到了其他老师分享的，有标注~
③仅限于在正规渠道由本人发布后下载获取，一切其他方式获得皆视为二传，抓到必究
④🍃⭕️←这个是可以调整的部分*/

/* ====== 全局字体====== */
@import url("https://fontsapi.zeoseven.com/19/main/result.css");

body {
    font-family: "LXGW Neo XiHei";
    font-weight: normal;
}
/*———————— 顶栏 ————————*/
#top-bar {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 80px;
    pointer-events: none;
    z-index: 1000; /* 确保足够高的层级 */
    background: none;
    border: 0;
    box-shadow: none;
    overflow: visible;
}

#top-bar::before {
    content: "";
    position: fixed;
    top: 5px; 
    left: 10px; 
    width: calc(100% - 20px);
    background: rgba(255, 255, 255, 0.4); 
    backdrop-filter: blur(32px); 
    -webkit-backdrop-filter: blur(12px); 
    border-radius: 20px; 
    box-shadow: 
        0 0 0 1.3px rgba(244, 194, 215, 0.1), 
        0px 10px 10px rgba(186, 200, 220, 0.25); 
    z-index: 4; 
    pointer-events: auto;
}


@media (max-width: 768px) {
    #top-bar {
        height: 0px; 
    }

    #top-bar::before {
        height: 30px;/*顶栏高度*/
    }
}


/* ⭕️顶栏装饰层 */
#top-bar::after {
    content: "";
    position: fixed;
    background: url("https://i.postimg.cc/qRsqtPDP/IMG-20250829-184836-d857fc0322.png") no-repeat center / contain;
    width: 290px;
    height: 220px;
    top: -89px;
    right: 45px;
    z-index: 6;
    pointer-events: none;
    transform-origin: top center;
}



/* —————面板背景———— */
.drawer-content {
  background-image: url(''); /* 面板背景 */
  background-size: cover; 
  background-position: center; 
  background-repeat: no-repeat; 
  background-attachment: fixed;
  margin-top: 6px; /* 顶部下移*/
}
/*毛玻璃@LiitleYE*/
body.no-blur .drawer-content {
background: rgba(255, 255, 255, 0.3); 
  backdrop-filter: blur(30px) !important;
}


/* ===== ⭕️楼层箭头、计数器核心 ===== */
.fa-chevron-right:before,
.fa-chevron-left:before,
.fa-arrow-right:before {
  content: "" !important;
  display: none !important; 
}

.fa-chevron-left,
.fa-chevron-right {
  display: inline-block;
  width: 14px;
  height: 14px; 
  min-width: 0;
  background: center/contain no-repeat;
}

.fa-chevron-left {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 左 */
  margin-bottom: -10px; 
}
.fa-chevron-right {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 右 */
  margin-bottom: -10px; 

}

/* ===== 楼层计数器样式 ===== */
.swipes-counter {
  font-size: 9px;
  font-weight: 540;
  opacity: 0.5 !important;
  color: #cbd5e1 !important;
  display: flex;
  justify-content: center;
  align-self: center;
  z-index: 3;
  min-width: 0;
  height: 20px;
  padding: 30px 10px 0; /* ①；需要联合②调整 */
  margin: 0 10px;
  margin-bottom: -10px;/*②；需要联合①调整*/
}

/* ==============================================
🦋气泡拼接开始🦋 *==============================================*/

/* 🍃上层装饰层、拼接气泡顶部 */
.mes::before {
  content: "";
  position: absolute;
  top: -113px; /* 【上下】(负值向上) */
  left: -8px; /* 【左右】 */
  width: 365px; /* 【宽度/大小】 */
  height: 530px; /* 【高度/大小】 */
  background-image: url('https://i.postimg.cc/kXxsJGys/IMG-20250829-184517-83e80f4f5f.png'); 
  background-size: contain; 
  background-repeat: no-repeat; 
  z-index: -2; 
  pointer-events: none; 
}

/* 🍃下层装饰层、拼接气泡尾部 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -60px; /* 【上下】(负值向下) */
  right: 102px; /* 下层装饰层【左右】 */
  width: 120px; /* 【宽度/大小】 */
  height: 90px; /* 【高度/大小👁会影响最新消息的底部留白，不可调太高，宽度拉不动再调高一点】 */
  background-image: url('https://i.postimg.cc/fRdNTxrF/IMG-20250829-185317-84488e6b13.png'); 
  background-size: contain; 
  background-repeat: no-repeat; 
  z-index: -4; 
  pointer-events: none; 
}

/* 🍃 中层气泡*/
.mes {
  z-index: -3;
  max-width: 330px;
  width: 100%;
  margin: 220px auto 0px;
  border-radius: 10px;
  position: relative;
  overflow: visible;
border: 1.5px solid #ffffff; 
  box-shadow: 
    0 0 8px rgba(255, 255, 255, 0.9), 
    0 0 16px rgba(191, 219, 254, 0.8), 
    0 0 24px rgba(147, 197, 253, 0.6);
}



/*毛玻璃@LiitleYE*/
body.no-blur .mes {
background: rgba(255, 255, 255, 0.6); 
  backdrop-filter: blur(70px) !important;
}

/*——————🍃文本边距——————*/

.mes_text,
.mes_reasoning {
    font-weight: 00;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: justify;
text-justify: inter-ideograph; /* 适合中文，保证均匀对齐 */
    overflow-wrap: anywhere;

    /* ⭕️文字边距核心*/

    --top-padding:6rem; /* 顶部 */
    --bottom-padding: 2rem; /* 底部 */
    --left-padding: 0rem; /* 左边距 */
    --right-padding: 0.5rem; /* 右边距 */

/*👁没啥用但不能删↓*/
    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);
    max-width: 100%;
    margin: 0; 
}

/* ==============================================
🦋气泡拼接结束🍃头像美化开始============================================== */


/*⭕️头像框*/
.mesAvatarWrapper {
  position: absolute;
  top: -147px;
  left: 28%;
  transform: translateX(-50%);
  z-index: -1;
  width: 70px;  
  height: 70px; 
  overflow: visible; 
}

/* ⭕️头像框位置与大小调整核心 */
.mesAvatarWrapper::after {
  content: "";
  position: absolute;
  top: 53%;/* 【上下】 */
  left: 154%;/* 【左右】 */
  width: 367%;  /* 【框宽度】 */
  height: 251%; /* 【框高度】 */
  display: block;

  /* ⭕️头像框链接放置处 */
  background-image: url('https://i.postimg.cc/vBNqVK1v/IMG-20250829-185508-9c61b85606.png');/*←🍃*/
  background-size: 100% 100%;
  background-repeat: no-repeat;
  background-position: center;
  transform: translate(-50%, -50%);
  z-index: 1; 

}

.mesAvatarWrapper img {
  position: relative;
  z-index: -1; 
}

/* ⭕️头像位置 */
.mesAvatarWrapper {
  position: absolute;
  top: -110px;           /* 【负值向上】 */
  left: 13%;            /* 【头像左右】 */
  transform: translateX(-50%);
  z-index: -1;
}

/* ⭕️头像尺寸*/
.mesAvatarWrapper .avatar {
  /* 🍃头像尺寸 */
  width: 154px;           /* 宽度 */
  height: 103px;          /* 高度 */
  transform: rotate(0deg); /* 旋转 */
/* 外观样式 */
  overflow: hidden;
  border: 0px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0);
  transition: all 0.3s ease;
}
.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}



/* ==============================================
🦋头像美化结束🍃文字效果美化开始============================================== */

/* === 设置选项=== */
small {
  color: #524548 !important;
  opacity: 0.8;
}
.toggle-description {
    color: #94a3b8;
}
#completion_prompt_manager .completion_prompt_manager_header div {
    color: #94a3b8; /*字符*/
}

.fa-solid::before, .fa-regular::before {
    vertical-align: middle;
    text-align: center;
}

.right_menu_button {
    padding: 1px;
    filter: none;
    color: #94a3b8 !important; /* 更新文字颜色 */
}

/* === 预设区文字颜色 === */
/* 选中 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  color: #76686b;
}

/* 未选 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, 
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  color: #94a3b8;
}

/* 星号等标识颜色*/
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt .completion_prompt_manager_prompt_name .fa-solid {
    color: #94a3b8;
}

/* 代码块 */
code, pre {
background: rgba(255, 255, 255, 0.95) !important;
color: #ada0a0 !important;
border: 0px solid rgba(208, 128, 172, 0.3) !important;
box-shadow: 
  inset 2px 2px 3px rgba(208, 128, 172, 0.05),
  0 0 12px rgba(208, 128, 172, 0.15),
  2px 2px 4px rgba(107, 102, 66, 0.05) !important;
border-radius: 12px 0px 12px 0px !important;
}

/* 引用气泡 */
.mes_text q {
  background: linear-gradient(90deg, rgba(192, 175, 175, 0.3) 0%, rgba(255, 255, 255, 0) 100%) !important; 
  border-radius: 8px !important;
  font-weight: 400;
  text-shadow: 0 0 4px rgba(219, 234, 254, 0.9), 
               0 0 6px rgba(219, 234, 254, 0.5),
               0 0 8px rgba(219, 234, 254, 0.2) !important;
  box-shadow: 0 0 4px rgba(147, 197, 253, 0.6) inset !important;
  animation: breathing-light 3s ease-in-out infinite !important;
  font-style: normal !important;

}

/* 引用区块 */
.mes_text blockquote, 
.mes_reasoning blockquote {
  border-left: 3px solid #ded6d6 !important; 
  background: linear-gradient(90deg, rgba(255, 255, 255, 0.2) 0%, rgba(191, 219, 254, 0.2) 100%) !important; 
  color: #ada0a0 !important; 
  border-radius: 0px 12px 0px 12px !important;
}

/* 斜体 */
em, i {
  background: linear-gradient(to bottom, 
    rgba(255, 220, 230, 0) 90%, 
    rgba(180, 175, 175, 0.8) 90%) !important; 
  font-style: normal !important;
}

/* ==============================================
🦋文字效果美化结束🍃零碎美化开始============================================== */

/*—— 🍃楼层 ——*/

.mes .mesIDDisplay {
    position: fixed;
    top: 46px;
    left: 160px;                    /* 从左侧开始定位 */
    transform: none;            /* 移除所有变换效果 */
    z-index: 2;
    margin-top: 0px;
    text-align: left;           /* 文字左对齐 */
    width: auto;                /* 宽度自适应内容 */
    white-space: nowrap;        /* 防止文字换行 */
    padding: 0 10px;            /* 添加左右内边距 */


    display: inline-flex; 
    align-items: center;  
    gap: 2px;            /* 【左右文字间距】 */

    cursor: default;
    opacity: 1;
    font-size: calc(var(--mainFontSize) * 0.8);
    font-weight: 300;
    color: #94a3b8;      /* 【主文字颜色】 */
}


/* 左侧文字 */
.mes .mesIDDisplay::before {
    content: var(--left-text, "A • 第"); /* 【左侧文字内容】 */
    white-space: nowrap;  
    color: var(--left-color, #94a3b8); /* 【左侧文字颜色】 */
    font-weight: 300;
}

/* 右侧文字 */
.mes .mesIDDisplay::after {
    content: var(--right-text, "  期杂志"); /* 【右侧文字内容】 */
    white-space: nowrap;  
    color: var(--right-color, #94a3b8); /* 【右侧文字颜色】 */
    font-weight: 300;
}

/*—— 🍃基础信息【时间戳、角色昵称等】 ——*/

/* ⭕️消息文字上边距留白核心调整 */
.mes_block {
  position: relative;
  margin-top: -120px;  
  overflow: visible;
}

/* ⭕️角色名称核心调整 */
.mes_block .ch_name {
  position: relative;
  top: -45.6px; /* 上下 */
  left: 43px;
  max-width: calc(100% - 105px); 
  min-height: 0px;
  z-index: 10; 
 font-size: 0.80em;
  font-weight: 800;
  letter-spacing: 0.9px;
white-space: nowrap;
}


/* 角色昵称颜色 */
.mes_block .ch_name {
  color: #94a3b8 !important; 
  text-shadow: none !important;
  -webkit-text-stroke: 0 !important; 
}

/* 时间戳颜色 */
.timestamp {
  color: #94a3b8 !important; 
  opacity: 1 !important; 
}


/* ⭕️时间戳核心调整 */
.timestamp {
  position: absolute;
  top: 53px;                /* 上下 */
  left: 108px;                /* 左右 */
  width: 300%; 
  font-size: 7px;            /* 字体大小 */
  font-weight: 500;          /* 字体粗细 */
  transform: rotate(0deg);   /* 旋转 */
  white-space: nowrap;
}

/* 左侧文字 */
.timestamp::before {
  content: "• 本期发布时间｜";       /*左侧文字 */
  color: #94a3b8;            /* 左侧文字颜色 */
  display: inline;
  padding-right: 0px;        /* 右侧间距（分隔时间戳） */
  pointer-events: none;
}

/* 右侧文字 */
.timestamp::after {
  content: "";       /* 右侧文字 */
  color: #64748b;            /* 右侧文字颜色 */
  display: inline;
  padding-left: 0px;         /* 左侧间距（分隔时间戳） */
  pointer-events: none;
}


/* ⭕️编辑按钮核心调整 */
.mes_buttons {
  position: relative;
  top: 108px; /*上下*/
  left: 73px;/*左右*/
  z-index: 30;
  padding: 20px; 
  min-height: 36px;
  box-sizing: border-box;
  transform: rotate(0deg); /* 旋转 */
}

.mes_edit_buttons {
    display: none;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 5px;
    filter: none; /*移除阴影*/
    transition: 0.3s ease-in-out;

    /* ⭕编辑菜单位置核心调整⭕ */
    position: relative;
    top: 140px;  /* 负数上移 | 正数下移  */
    right: 0px;   /* 负数右移 | 正数左移  */
  transform: rotate(0deg); /* 旋转 */
}
.mes_edit_down.menu_button.fa-solid.fa-chevron-down.interactable.disabled {
    filter: none !important;
}
.mes_button, .extraMesButtons>div {
cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    filter: drop-shadow(0px 0px 0px #ffffff) !important;
    /* ⭕设置省略号菜单颜色 */
    color: #94a3b8 !important;
opacity: 0.4 !important; 
}


/*—— 计时器&字符——*/
.mes {
  position: relative; 
}

.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; 
  z-index: 3; 
  cursor: default;
opacity: 1;/*透明度*/
  white-space: nowrap; 
  font-size: calc(var(--mainFontSize) * 0.8);/*文字大小*/
  font-weight: 400;/*文字粗细*/
  padding: 0;
  top: var(--element-top, 248px);
  left: var(--element-left, 50%);
  transform: translateX(var(--element-translate, -50%));
}


/* === ⭕️计时器核心 === */
.mes .mes_timer {
  --element-top: var(--timer-top, 81px); /*【🍃计时器上下】*/
  --timer-left: 169px; /* 🍃计时器左右 */
  --timer-translate: 0; 
  text-align: left; 
  left: var(--timer-left);
  transform: translate(var(--timer-translate), -50%);

  /* 文字内容控制 */
  --timer-prefix: "C •   "; /* 【🍃前缀】 */
  --timer-suffix: "售空"; /* 【🍃后缀】 */

  --timer-main-color: #94a3b8; /* 【🍃计时器颜色】 */
  --timer-prefix-color: #94a3b8; /* 【🍃前缀颜色】 */
  --timer-suffix-color: #94a3b8; /* 【🍃后缀颜色】 */

  color: var(--timer-main-color);
}

/* 计时器文字控制 */
.mes .mes_timer::before {
  content: var(--timer-prefix); /* 前缀文字 */
  color: var(--timer-prefix-color);
  padding-right: 0px;
}
.mes .mes_timer::after {
  content: var(--timer-suffix); /* 后缀文字 */
  color: var(--timer-suffix-color);
  padding-left: 0px;
}

/* === 字符计数器单独设置 === */
.mes .tokenCounterDisplay {
  text-align: left;
  --element-top: var(--counter-top, 60px); /* 【🍃字符计数器上下】 */
  --element-left: var(--counter-left, 243%); /* 【🍃字符计数器左右】 */
  --element-translate: var(--counter-translate, -0%); 

  --counter-prefix: "B • 总订阅者"; /* 【🍃前缀】 */
  --counter-suffix: ""; /* 【🍃后缀】 */

  --counter-main-color: #94a3b8; /* 【🍃计数器颜色】 */
    --counter-prefix-color: #94a3b8; /* 【🍃前缀颜色】 */
  --counter-suffix-color: #94a3b8; /* 【🍃后缀颜色】 */
  color: var(--counter-main-color);

}

.mes .tokenCounterDisplay::before {
  content: var(--counter-prefix); /* 前缀文字 */
  color: var(--counter-prefix-color);
  padding-right: 0px;
}
.mes .tokenCounterDisplay::after {
  content: var(--counter-suffix); /* 后缀文字 */
  color: var(--counter-suffix-color);
  padding-left: 0px;
}

/*—— ⭕️外显思维链 ——*/
.mes_reasoning_header {
  position: absolute;
  z-index: 9999;
  top: 87px;
  left: 66%;
  transform: translateX(-50%);
  cursor: pointer;
  user-select: none;
  font-size: calc(var(--mainFontSize) * 0.75);
  transition: all 0.3s ease;

  padding: 1px 15px;
  background: linear-gradient(90deg, 
              rgba(229, 206, 211, 0.5) 0%, 
              rgba(255, 255, 255, 0) 100%);
  border: none;
  border-radius: 0;
  box-shadow: 
    0 4px 12px rgba(107, 102, 66, 0.08),
    0 2px 4px rgba(107, 102, 66, 0.04);
  color: #ffffff;
  backdrop-filter: blur(4px);
}

.mes_reasoning_header:hover {
  transform: translateX(-50%) translateY(1px);
  opacity: 0.92;
  background: linear-gradient(90deg, 
              rgba(255, 255, 255, 0.95) 0%, 
              rgba(255, 255, 255, 0.1) 100%);
  box-shadow: 
    0 2px 6px rgba(107, 102, 66, 0.05),
    0 1px 2px rgba(107, 102, 66, 0.02);
}

.mes_reasoning_header_title {
  position: relative;
  display: inline-block;
  top: 0px;
  left: -0px;
  color: #a28d9a;
  font-weight: 400;
  letter-spacing: 0.5px;
  text-shadow: 0 1px 1px rgba(255, 255, 255, 0.7);
}

.mes_reasoning {
  position: relative;
  top: -190px;
  display: block;
  margin: 235px 0px -240px;

  color: #8a7a78;
  background: linear-gradient(90deg, 
              rgba(255, 197, 217, 0.12) 0%, 
              rgba(255, 255, 255, 0) 70%);
  border: none;
  box-shadow: 
    0 8px 24px rgba(107, 102, 66, 0.1),
    0 2px 6px rgba(107, 102, 66, 0.05);
  padding: 18px 20px;
  line-height: 2.5;
  border-radius: 0px;

  background-image: none;
  backdrop-filter: blur(8px);
}
.mes_reasoning_header_title {
  /* 隐藏原始文本 */
  font-size: 0; 
  color: transparent; 
}

.mes_reasoning_header_title::before {
  /*⭕️思维链文字diy */
  content: "💙 𝐒𝐡𝐡, 𝐈’𝐦 𝐭𝐡𝐢𝐧𝐤𝐢𝐧𝐠.";
  font-size: 5.5px; /* 字号 */
  color: #5C6F91;   /* ← 灰蓝，替代 #cebbbf */
  font-style: normal; 
  font-weight: 200; 
}

这部分没改色



/*—— 分割线 ——*/
hr {
    all: unset !important; 
    display: block !important;
    visibility: visible !important;
    background-image: none !important; 
    height: auto !important; 
    min-height: unset !important;
    margin: 0 !important;
    opacity: 1 !important;
    position: relative;
}
hr::after {
    content: "" !important;
