/*————⭕️一些功能————*/

/* 隐藏qr功能（来自@junezz 老师） */
#send_form:hover #qr--bar {
  height: 31px;    
  transition: all 0.5s ease;
}
#qr--bar {    
  height: 0.1px;
}

/* 正则留空 */
.regex-script-label {
    max-width: 80%; 
}

/*qr留空*/
#qr--settings .qr--setList > .qr--item {
    position: relative;
    left: -25px;
    transform: translateX(-15px);
    padding: 12px 20px 12px 5px;
    margin: 8px 0;
    border-radius: 0 12px 12px 0;
    box-shadow: -3px 3px 8px rgba(0,0,0,0.1);
}

/*去除小黑点@nini*/
#send_textarea {
  resize: none; 
}

/*——————⭕滚动条调整——————*/

::-webkit-scrollbar {
  width: 0px;/*滚动条大小，默认隐藏*/
  height: 8px; 
}



/*输入框渐变*/
#chat {
  /* 保留你原有的样式 */
  max-height: calc(100vh - calc(var(--topBarBlockSize) + var(--bottomFormBlockSize)));
  overflow-x: hidden;
  padding-bottom: 0;
  overflow-y: scroll;
  display: flex;
  bottom: 10px;
  backdrop-filter: blur(var(--SmartThemeBlurStrength));
  background-color: var(--SmartThemeChatTintColor);
  -webkit-backdrop-filter: blur(var(--SmartThemeBlurStrength));
  text-shadow: 0px 0px calc(var(--shadowWidth) * 1px) var(--SmartThemeShadowColor);
  flex-direction: column;
  z-index: 30;
  flex-grow: 1;

/* 更柔和的渐变 */
mask-image: linear-gradient(
  to bottom, 
  rgba(0,0,0,1) 0%, 
  rgba(0,0,0,1) 90%, 
  rgba(0,0,0,0) 100%
);


input {
  border: 1px solid rgba(255, 255, 255, 0.6);     /* 柔和白描边 */
  box-shadow: 
    0 0 4px rgba(255, 255, 255, 0.4),            /* 内圈轻光 */
    0 0 8px rgba(191, 219, 254, 0.3);            /* 外圈淡蓝光 */
  border-radius: 8px;
}


p {
  margin-top: 0;
  margin-bottom: 1em; /* 调整段落之间的空隙 */
  line-height: 1.4;     /* 行距保持你原来的值 */
}

p + p {
  margin-top: 1em; /* 段落之间的额外间距 */
}

br {
  line-height: normal;
  display: block;
  margin-bottom: 0.8em; /* 换行后的额外空隙 */
  content: "";
}
